package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
)

func handleRequest(w http.ResponseWriter, r *http.Request) {
	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Error reading request body", http.StatusInternalServerError)
		return
	}
	defer r.Body.Close()

	// Print the request body
	fmt.Println("Request Content:", string(body))

	// Send a response back to the client
	w.Header().Set("Content-Type", "text/plain")
	w.Write([]byte("Request content received and printed successfully."))
}

func main() {
	// Set up the HTTP server
	http.HandleFunc("/", handleRequest)

	// Start the server on port 8080
	fmt.Println("Server is running on http://localhost:8080/")
	http.ListenAndServe(":8080", nil)
}
```

### Explanation:
1. **Reading the Request Body**: The `ioutil.ReadAll` function is used to read the entire request body. This is necessary because the `http.Request.Body` is a stream and reading it twice will return an error.
