In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions. You'll need to use `dup2()` to redirect the file descriptor. Here's a step-by-step example:

1. **Fork the Process:** Create a new process using `fork()`.
2. **Close Unnecessary Descriptors:** Close the descriptors that are not needed in the child process.
3. **Redirect File Descriptors:** Use `dup2()` to redirect the file descriptor to the standard input/output of the child process.
4. **Execute the Program:** Use `exec()` to execute the desired program in the child process.

Here's a complete example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <fcntl.h>
#include <stdio.h>

int main() {
    int fd[2];  // Pipe file descriptors
    pid_t pid;

    // Create a pipe
    if (pipe(fd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a new process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        return 1;
    }

    if (pid == 0) {  // Child process
        // Close the unused ends of the pipe
        close(fd[1]);  // Close write end in child

        // Redirect stdin to the read end of the pipe
        dup2(fd[0], STDIN_FILENO);
        close(fd[0]);  // Close the read end after redirection

        // Execute the program
        execlp("cat", "cat", NULL);  // Example: use 'cat' as the program
        perror("execlp");
        _exit(1);
    } else {  // Parent process
        // Close the unused ends of the pipe
        close(fd[0]);  // Close read end in parent

        // Write to the write end of the pipe
        const char* message = "Hello, World!\n";
        write(fd[1], message, strlen(message));

        // Close the write end
        close(fd[1]);

        // Wait for the child to finish
        wait(NULL);
    }

    return 0;
}
```

